/**
 * @summary Create a recurring template from an existing task
 */
export const CreateTaskRecurrenceParams = zod.object({
  "taskId": zod.coerce.number()
})

export const createTaskRecurrenceBodyTimeOfDayRegExp = new RegExp('^([01][0-9]|2[0-3]):[0-5][0-9]$');
export const createTaskRecurrenceBodyDayOfWeekMin = 0;
export const createTaskRecurrenceBodyDayOfWeekMax = 6;

export const createTaskRecurrenceBodyDayOfMonthMax = 31;



export const CreateTaskRecurrenceBody = zod.object({
  "columnId": zod.number(),
  "frequency": zod.enum(['hourly', 'daily', 'weekly', 'monthly']),
  "timeOfDay": zod.string().regex(createTaskRecurrenceBodyTimeOfDayRegExp).optional(),
  "dayOfWeek": zod.number().min(createTaskRecurrenceBodyDayOfWeekMin).max(createTaskRecurrenceBodyDayOfWeekMax).optional(),
  "dayOfMonth": zod.number().min(1).max(createTaskRecurrenceBodyDayOfMonthMax).optional()
})

export const CreateTaskRecurrenceResponse = zod.object({
  "id": zod.number(),
  "projectId": zod.number(),
  "columnId": zod.number(),
  "columnName": zod.string(),
  "title": zod.string(),
  "description": zod.string().nullish(),
  "type": zod.enum(['standard', 'video']),
  "priority": zod.enum(['low', 'medium', 'high']),
  "frequency": zod.enum(['hourly', 'daily', 'weekly', 'monthly']),
  "timeOfDay": zod.string().nullish(),
  "dayOfWeek": zod.number().nullish(),
  "dayOfMonth": zod.number().nullish(),
  "active": zod.boolean(),
  "nextRunAt": zod.string(),
  "lastRunAt": zod.string().nullish(),
  "createdAt": zod.string()
})


